import pandas as pd

def calculate_score(post, keywords):
    score = 0
    if post:
        score += len(post) / 280 * 5 # Score based on length utilization
        for keyword in keywords:
            if keyword.lower() in post.lower():
                score += 2 # Bonus for keyword presence
    return round(min(score, 10), 2)

